 *   shared key using their own private ECDH key + recipient's ECDH public key).
 *   Fix: remove the short-circuit; send own messages through the same
 *   decryptMessage() path but pass the peer's ECDH key as senderECDHPublicKeyPEM.
 *
 * BUG B — Duplicate messages when both socket events fire for the sender
 *   'message_sent' and 'receive_message' can both fire for the sender.
 *   The original code appends on both events with no dedup → duplicates.
 *   Fix: deduplicate by message id before appending.
 *
 * BUG C — Socket listeners re-register on every selected-contact change
 *   The cleanup in the existing useEffect removes the *current* listeners,
 *   but only after they were added — if `selected` changes rapidly the old
 *   listener closure still references the old `selected` value.
 *   Fix: use a ref for `selected` inside the socket listener.
 *
 * BUG D — keyError banner shows a generic warning with no recovery action
 *   Fix: show a structured message with a link to the key-import flow.
 */

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useNavigate }  from 'react-router-dom';
import { useAuth }      from '../context/AuthContext';
import { useSocket }    from '../context/SocketContext';
import { useTheme }     from '../context/ThemeContext';
import api              from '../services/api';
import { loadKeysFromSession, encryptMessage, decryptMessage } from '../utils/crypto';
import styles from './ChatPage.module.css';

export default function ChatPage() {
  const { user, token, logout }            = useAuth();
  const { socket, connected, onlineUsers } = useSocket();
  const { theme, toggle }                  = useTheme();
  const navigate = useNavigate();

  const [contacts,       setContacts]       = useState([]);
  const [search,         setSearch]         = useState('');
  const [selected,       setSelected]       = useState(null);
  const [messages,       setMessages]       = useState([]);
  const [input,          setInput]          = useState('');
  const [peerTyping,     setPeerTyping]     = useState(false);
  const [cryptoKeys,     setCryptoKeys]     = useState(null);
  const [keyError,       setKeyError]       = useState(false);
  const [decryptedCache, setDecryptedCache] = useState({});

  const messagesEndRef = useRef(null);
  const typingTimeout  = useRef(null);
  const isTyping       = useRef(false);
  // FIX C — stable ref to selected so socket listeners always see current value
  const selectedRef    = useRef(null);
  useEffect(() => { selectedRef.current = selected; }, [selected]);

  // ── Load crypto keys from storage ─────────────────────────────────────────
  useEffect(() => {
    loadKeysFromSession().then(k => {
      if (k) {
        setCryptoKeys(k);
      } else {
        setKeyError(true);
        // FIX — also try localStorage (may have been written at login time)
        import('../utils/crypto').then(({ loadKeysFromLocal }) => {
          if (user?.id) {
            loadKeysFromLocal(user.id).then(lk => {
              if (lk) { setCryptoKeys(lk); setKeyError(false); }
            });
          }
        });
      }
    });
  }, [user?.id]);

  // ── Fetch contacts ─────────────────────────────────────────────────────────
  useEffect(() => {
    api.get('/api/users', { params: { search } }).then(r => setContacts(r.data));
  }, [search]);

  // ── Fetch messages for selected contact ───────────────────────────────────
  useEffect(() => {
    if (!selected) return;
    setMessages([]);
    setDecryptedCache({});
    api.get(`/api/messages/${selected.id}`)
      .then(r => setMessages(r.data.messages || []));
  }, [selected]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // ── Decrypt messages lazily ────────────────────────────────────────────────
  useEffect(() => {
    if (!cryptoKeys || !selected || !messages.length) return;
    messages.forEach(async msg => {
      if (decryptedCache[msg.id]) return;

      // FIX A — decrypt own messages via ECDH (same shared key, both directions)
      // The senderECDHPublicKeyPEM for own messages is the *recipient's* ECDH key,
      // which we already have in selected.ecdh_public_key.
      const isMine = msg.sender_id === user.id;

      try {
        const result = await decryptMessage({
          encryptedMsg:              msg,
          myPrivateECDHKey:          cryptoKeys.privateECDHKey,
          // For own messages: derive shared key using recipient's public ECDH key
          // For received messages: derive using sender's public ECDH key
          senderECDHPublicKeyPEM:    selected.ecdh_public_key,
          senderRSASignPublicKeyPEM: isMine ? null : selected.public_key,
        });
        setDecryptedCache(c => ({ ...c, [msg.id]: result }));
      } catch {
        setDecryptedCache(c => ({
          ...c, [msg.id]: { plaintext: '[Decryption error]', verified: false, hashOk: false }
        }));
      }
    });
  }, [messages, selected, cryptoKeys, decryptedCache, user?.id]);

  // ── Socket listeners ───────────────────────────────────────────────────────
  // FIX B — deduplicate messages by id
  const addMessage = useCallback(msg => {
    setMessages(prev => {
      if (prev.some(m => m.id === msg.id)) return prev;  // already present
      return [...prev, msg];
    });
  }, []);

  useEffect(() => {
    if (!socket) return;

    // FIX C — use selectedRef to avoid stale closure over `selected`
    const onReceive = msg => {
      const sel = selectedRef.current;
      if (sel && (msg.sender_id === sel.id || msg.recipient_id === sel.id)) {
        addMessage(msg);
      }
    };

    // 'message_sent' fires on the sender's socket — use the same dedup helper
    const onSent     = msg => addMessage(msg);
    const onTyping   = ({ user_id }) => {
      if (selectedRef.current?.id === user_id) setPeerTyping(true);
    };
    const onStopType = ({ user_id }) => {
      if (selectedRef.current?.id === user_id) setPeerTyping(false);
    };

    socket.on('receive_message',  onReceive);
    socket.on('message_sent',     onSent);
    socket.on('user_typing',      onTyping);
    socket.on('user_stop_typing', onStopType);

    return () => {
      socket.off('receive_message',  onReceive);
      socket.off('message_sent',     onSent);
      socket.off('user_typing',      onTyping);
      socket.off('user_stop_typing', onStopType);
    };
  }, [socket, addMessage]);

  // ── Send message ───────────────────────────────────────────────────────────
  const sendMessage = async () => {
    if (!input.trim() || !selected || !cryptoKeys || !socket) return;
    const plaintext = input.trim();
    setInput('');
    try {
      const payload = await encryptMessage({
        plaintext,
        myPrivateSignKey:          cryptoKeys.privateSignKey,
        myPrivateECDHKey:          cryptoKeys.privateECDHKey,
        recipientECDHPublicKeyPEM: selected.ecdh_public_key,
        recipientRSAPublicKeyPEM:  selected.public_key,
      });
      socket.emit('send_message', { token, recipient_id: selected.id, ...payload });
    } catch (err) {
      console.error('[CipherLink] Encrypt error:', err);
    }
  };

  const handleKeyDown = e => {
    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); sendMessage(); return; }
    if (!isTyping.current && socket && selected) {
      isTyping.current = true;
      socket.emit('typing', { token, recipient_id: selected.id });
    }
    clearTimeout(typingTimeout.current);
    typingTimeout.current = setTimeout(() => {
      isTyping.current = false;
      if (socket && selected) socket.emit('stop_typing', { token, recipient_id: selected.id });
    }, 1500);
  };

  const VerifyBadge = ({ verified, hashOk }) =>
    verified && hashOk
      ? <span title="Signature verified · Hash OK" style={{ color: 'var(--success)', fontSize: 11 }}>✔✔</span>
      : <span title="Verification failed!" style={{ color: 'var(--danger)', fontSize: 11 }}>⚠️</span>;

  return (
    <div className={styles.layout}>
      {/* Sidebar */}
      <aside className={styles.sidebar}>
        <div className={styles.sidebarHeader}>
          <div className={styles.brandRow}>
            <span className={styles.brand}>🔐 CipherLink</span>
            <div className={styles.headerActions}>
              <button onClick={toggle} className={styles.iconBtn}>
                {theme === 'light' ? '🌙' : '☀️'}
              </button>
              <button onClick={logout} className={styles.iconBtn} title="Logout">⏻</button>
            </div>
          </div>
          <div className={styles.userInfo}>
            <span className={`${styles.dot} ${connected ? styles.online : styles.offline}`} />
            <span className={styles.username}>{user?.username}</span>
          </div>
          <input className={styles.search} placeholder="Search users…"
                 value={search} onChange={e => setSearch(e.target.value)} />
        </div>

        <div className={styles.contactList}>
          {contacts.length === 0 && (
            <div className={styles.empty}>No users found</div>
          )}
          {contacts.map(c => (
            <div key={c.id}
                 className={`${styles.contact} ${selected?.id === c.id ? styles.active : ''}`}
                 onClick={() => setSelected(c)}>
              <div className={styles.avatar}>{c.username[0].toUpperCase()}</div>
              <div className={styles.contactInfo}>
                <span className={styles.contactName}>{c.username}</span>
                <span className={styles.contactStatus}>
                  {onlineUsers.has(c.id) ? '🟢 Online' : '⚫ Offline'}
                </span>
              </div>
            </div>
          ))}
        </div>
      </aside>

      {/* Main */}
      <main className={styles.main}>

        {/* FIX D — structured key-error banner with recovery action */}
        {keyError && (
          <div className={styles.keyWarning}>
            🔑 <strong>Encryption keys not found for this session.</strong>{' '}
            This happens when you log in from a new tab or browser.{' '}
            <button
              onClick={() => navigate('/login')}
              style={{ background: 'none', border: 'none', color: 'var(--accent)',
                       fontWeight: 600, cursor: 'pointer', padding: 0 }}>
              Go to login to import your key backup
            </button>
            {' '}or{' '}
            <button
              onClick={() => navigate('/register')}
              style={{ background: 'none', border: 'none', color: 'var(--accent)',
                       fontWeight: 600, cursor: 'pointer', padding: 0 }}>
              create a new account
            </button>.
          </div>
        )}

        {!selected ? (
          <div className={styles.placeholder}>
            <div className={styles.placeholderIcon}>🔐</div>
            <h2>Select a contact to start chatting</h2>
            <p>All messages are end-to-end encrypted</p>
            <div className={styles.cryptoBadges}>
              <span>AES-256-GCM</span>
              <span>RSA-2048</span>
              <span>ECDH P-256</span>
              <span>SHA-256</span>
            </div>
          </div>
        ) : (
          <>
            <div className={styles.chatHeader}>
              <div className={styles.avatar} style={{ width: 36, height: 36, fontSize: 16 }}>
                {selected.username[0].toUpperCase()}
              </div>
              <div>
                <div className={styles.chatHeaderName}>{selected.username}</div>
                <div className={styles.chatHeaderStatus}>
                  {onlineUsers.has(selected.id) ? '🟢 Online' : '⚫ Offline'} · 🔒 E2E Encrypted
                </div>
              </div>
            </div>

            <div className={styles.messages}>
              {messages.map(msg => {
                const isMine = msg.sender_id === user.id;
                const dec    = decryptedCache[msg.id];
                return (
                  <div key={msg.id}
                       className={`${styles.msgRow} ${isMine ? styles.mine : styles.theirs}`}>
                    <div className={`${styles.bubble} ${isMine ? styles.bubbleMine : styles.bubbleTheirs}`}>
                      {/* FIX A — show actual plaintext for own messages */}
                      <div className={styles.msgText}>
                        {dec
                          ? dec.plaintext
                          : <span style={{ opacity: 0.6, fontStyle: 'italic' }}>🔓 Decrypting…</span>
                        }
                      </div>
                      <div className={styles.msgMeta}>
                        <span>{new Date(msg.timestamp).toLocaleTimeString()}</span>
                        {/* Only show verify badge for received messages */}
                        {dec && !isMine && (
                          <VerifyBadge verified={dec.verified} hashOk={dec.hashOk} />
                        )}
                        {msg.is_read ? ' ✓✓' : msg.is_delivered ? ' ✓' : ' ○'}
                      </div>
                    </div>
                  </div>
                );
              })}

              {peerTyping && (
                <div className={`${styles.msgRow} ${styles.theirs}`}>
                  <div className={`${styles.bubble} ${styles.bubbleTheirs} ${styles.typing}`}>
                    <span /><span /><span />
                  </div>
                </div>
              )}
              <div ref={messagesEndRef} />
            </div>

            <div className={styles.inputArea}>
              <div className={styles.encryptBadge}>🔒 AES-256-GCM</div>
              <textarea
                className={styles.input}
                placeholder={
                  cryptoKeys
                    ? 'Type a message… (Enter to send)'
                    : '⚠️ Keys missing — cannot send encrypted messages'
                }
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyDown={handleKeyDown}
                rows={1}
                disabled={!cryptoKeys}
              />
              <button
                className={styles.sendBtn}
                onClick={sendMessage}
                disabled={!input.trim() || !cryptoKeys}>
                ➤
              </button>
            </div>
          </>
        )}
      </main>
    </div>
  );
}
